-- EVENTS
on conflict (slug) do update set
  image_url = excluded.image_url,
  name = excluded.name,
  type = excluded.type,
  impact = excluded.impact,
  date_display = excluded.date_display,
  location = excluded.location,
  description = excluded.description,
  has_detail = excluded.has_detail;

-- EVENT CONTENT BLOCKS
select e.id, v.sort_order, v.content
from public.events e
join (values
  ('above-and-beyond-open-house', 0, 'Above and Beyond Open House menjadi salah satu momen penting dalam perjalanan perusahaan, menghadirkan kesempatan bagi para tamu dan mitra untuk mengenal lebih dekat visi serta perkembangan yang telah dicapai.'),
  ('above-and-beyond-open-house', 1, 'Acara ini dirancang dengan konsep open house yang fleksibel dan mengalir secara natural, memungkinkan para tamu untuk berinteraksi, berdiskusi, dan merasakan atmosfer kolaboratif yang menjadi nilai utama dari Clapham Collective.'),
  ('above-and-beyond-open-house', 2, 'Dengan dukungan teknis yang optimal serta koordinasi tim yang solid, seluruh rangkaian acara berjalan tertata dengan baik dan menciptakan pengalaman yang hangat serta berkesan bagi setiap tamu yang hadir.'),
  ('above-and-beyond-seminar-100', 0, 'Above and Beyond Seminar menjadi seminar perdana yang diselenggarakan oleh klien dengan tujuan menghadirkan ruang berbagi pengetahuan dan inspirasi bagi para peserta.'),
  ('above-and-beyond-seminar-100', 1, 'Acara ini berhasil menarik total 40 peserta, melampaui target awal yang telah direncanakan. Hal ini menunjukkan antusiasme yang tinggi dari peserta terhadap topik yang dibawakan.'),
  ('above-and-beyond-seminar-100', 2, 'Dengan koordinasi tim yang rapi, eksekusi teknis yang berjalan baik, serta alur acara yang terkelola secara efektif, seminar ini berlangsung lancar dan menjadi fondasi kuat bagi pengembangan program-program selanjutnya.'),
  ('clapham-conference-2025', 0, 'Konferensi adalah sebuah forum pertemuan yang mempertemukan para profesional, pelaku usaha, akademisi, dan komunitas untuk berbagi pengetahuan, pengalaman, serta gagasan yang dapat mendorong kemajuan di berbagai bidang. Melalui sesi diskusi, presentasi, dan networking, konferensi menjadi ruang penting untuk bertukar perspektif, memperluas wawasan, dan membangun kolaborasi yang berdampak nyata.'),
  ('clapham-conference-2025', 1, 'Clapham Conference hadir sebagai wadah kolaborasi yang mempertemukan peserta dari berbagai industri untuk saling belajar dan berkembang bersama. Acara ini menghadirkan pembicara inspiratif serta membuka ruang diskusi yang mendorong lahirnya ide-ide baru dan solusi yang relevan dengan tantangan dunia bisnis dan teknologi saat ini.'),
  ('clapham-conference-2025', 2, 'Lebih dari sekadar acara berbagi pengetahuan, konferensi ini bertujuan memperkuat ekosistem inovasi di Kota Medan. Dengan mempertemukan pelaku usaha, startup, profesional, dan komunitas kreatif, Clapham Conference mendorong terciptanya kolaborasi yang dapat melahirkan peluang usaha baru, meningkatkan kualitas sumber daya manusia, serta mempercepat pertumbuhan ekonomi lokal.'),
  ('clapham-conference-2025', 3, 'Melalui berbagai topik seperti teknologi, strategi bisnis, hingga perkembangan industri kreatif, konferensi ini diharapkan mampu menginspirasi generasi muda dan pelaku usaha untuk terus berinovasi. Dengan semangat kolaborasi dan pembelajaran bersama, Clapham Conference berkomitmen menjadi bagian dari upaya membangun kota yang lebih maju, adaptif, dan berkelanjutan.'),
  ('brand-experience-festival', 0, 'Brand Experience Festival adalah event yang menggabungkan experiential marketing dengan entertainment untuk menciptakan pengalaman brand yang tak terlupakan. Dengan engagement rate mencapai 85% dari target audiens, festival ini membuktikan bahwa pendekatan experiential adalah cara paling efektif untuk membangun koneksi brand.'),
  ('brand-experience-festival', 1, 'Festival ini menghadirkan instalasi interaktif dari 12 brand ternama, masing-masing dirancang untuk mengajak pengunjung merasakan nilai dan cerita brand secara langsung. Dari virtual reality experience hingga hands-on workshop, setiap booth menawarkan sesuatu yang unik dan memorable.'),
  ('brand-experience-festival', 2, 'Tim Clapham Collective merancang setiap detail festival ini dengan cermat, mulai dari flow pengunjung, lighting design, hingga soundtrack yang mengiringi setiap zona. Hasilnya adalah sebuah pengalaman holistik yang tidak hanya menghibur tetapi juga meninggalkan kesan mendalam tentang setiap brand yang berpartisipasi.'),
  ('community-creative-gathering', 0, 'Community Creative Gathering adalah event rutin yang menjadi rumah bagi lebih dari 200 anggota komunitas kreatif aktif di Medan. Acara ini dirancang sebagai ruang aman dan inklusif bagi para kreator, desainer, seniman, dan inovator untuk bertemu, berbagi, dan berkolaborasi.'),
  ('community-creative-gathering', 1, 'Setiap pertemuan menghadirkan tema yang berbeda, mulai dari design thinking, creative entrepreneurship, hingga digital art dan photography. Format acara yang casual namun berstruktur memungkinkan peserta untuk belajar dari sesama kreator sambil membangun jaringan yang organik.'),
  ('community-creative-gathering', 2, 'Gathering ini telah melahirkan berbagai proyek kolaboratif yang sukses, mulai dari pameran seni bersama, zine community, hingga creative agency yang didirikan oleh anggota komunitas. Ini membuktikan bahwa ketika kreator bertemu dalam lingkungan yang tepat, hal-hal luar biasa bisa terjadi.'),
  ('creative-workshop-series', 0, 'Creative Workshop Series adalah program workshop bulanan yang telah berjalan sepanjang tahun 2024, menghadirkan 12 workshop dengan total lebih dari 400 peserta. Setiap bulan, workshop mengangkat topik yang berbeda untuk mengembangkan keterampilan praktis di bidang kreatif.'),
  ('creative-workshop-series', 1, 'Topik workshop mencakup spektrum luas dari dunia kreatif, mulai dari typography dan brand identity design, photography dan videography, creative writing, hingga UI/UX design dan motion graphics. Setiap workshop dipandu oleh praktisi berpengalaman yang aktif di industrinya.'),
  ('creative-workshop-series', 2, 'Yang membuat program ini istimewa adalah pendekatan hands-on yang diterapkan. Setiap peserta mengerjakan proyek nyata selama workshop dan pulang dengan portfolio piece yang bisa langsung digunakan. Banyak alumni workshop yang kemudian berhasil memulai karir kreatif mereka atau meningkatkan kualitas pekerjaan mereka secara signifikan.')
) as v(slug, sort_order, content) on e.slug = v.slug
on conflict (event_id, sort_order) do update set content = excluded.content;

