  ('clapham-conference-2025', 1, 'Pembicara inspiratif dari berbagai bidang'),
  ('clapham-conference-2025', 2, 'Diskusi dan networking antar pelaku usaha dan profesional'),
  ('clapham-conference-2025', 3, 'Ruang lahirnya ide bisnis dan inovasi baru'),
  ('clapham-conference-2025', 4, 'Mendorong pertumbuhan ekosistem bisnis di Kota Medan'),
